1	export type Command = {
2	  id: string;
3	  label: string;
4	  execute: () => void;
5	  enabled?: () => boolean;
6	};
7	
8	export class CommandRegistry {
9	  private commands = new Map<string, Command>();
10	
11	  register(command: Command): void {
12	    this.commands.set(command.id, command);
13	  }
14	
15	  unregister(id: string): void {
16	    this.commands.delete(id);
17	  }
18	
19	  execute(id: string): boolean {
20	    const command = this.commands.get(id);
21	    if (command === undefined) {
22	      return false;
23	    }
24	    if (command.enabled !== undefined && !command.enabled()) {
25	      return false;
26	    }
27	    command.execute();
28	    return true;
29	  }
30	
31	  getAll(): readonly Command[] {
32	    return [...this.commands.values()];
33	  }
34	
35	  get(id: string): Command | undefined {
36	    return this.commands.get(id);
37	  }
38	}
