1	import { useCallback, useEffect, useMemo, useRef, useState } from "react";
2	import { useDawStore } from "@state/store";
3	import { isMidiClip } from "@state/track/types";
4	import { CommandRegistry } from "@ui/keyboard/command-registry";
5	import { ShortcutMap } from "@ui/keyboard/shortcut-map";
6	import { useKeyboardShortcuts } from "@ui/keyboard/useKeyboardShortcuts";
7	import {
8	  renderPianoRoll,
9	  type PianoRollViewState,
10	  type PianoRollTool,
11	} from "./piano-roll-renderer";
12	import type { PianoRollGridSnap } from "./piano-roll-hit-test";
13	import { usePianoRollInteractions } from "./use-piano-roll-interactions";
14	import {
15	  PR_DEFAULT_NOTE_HEIGHT,
16	  PR_KEYBOARD_WIDTH,
17	  PR_DEFAULT_PPS,
18	  PR_DEFAULT_SCROLL_Y,
19	  PR_VELOCITY_LANE_HEIGHT,
20	  PR_MIN_NOTE,
21	  PR_MAX_NOTE,
22	} from "./constants";
23	import styles from "./PianoRollEditor.module.css";
24	
25	const DEFAULT_VIEW: PianoRollViewState = {
26	  scrollX: 0,
27	  scrollY: PR_DEFAULT_SCROLL_Y,
28	  pixelsPerSecond: PR_DEFAULT_PPS,
29	  noteHeight: PR_DEFAULT_NOTE_HEIGHT,
30	  keyboardWidth: PR_KEYBOARD_WIDTH,
31	};
32	
33	const MIN_PPS = 20;
34	const MAX_PPS = 500;
35	const ZOOM_FACTOR = 1.1;
36	
37	const SNAP_OPTIONS: readonly PianoRollGridSnap[] = [
38	  "1/4",
39	  "1/8",
40	  "1/16",
41	  "1/8T",
42	  "1/16T",
43	];
44	
45	type PianoRollEditorProps = {
46	  clipId: string | null;
47	  onNotePreview?: (note: number, velocity: number) => void;
48	  onNotePreviewEnd?: (note: number) => void;
49	};
50	
51	export function PianoRollEditor({
52	  clipId,
53	  onNotePreview: _onNotePreview,
54	  onNotePreviewEnd: _onNotePreviewEnd,
55	}: PianoRollEditorProps): React.JSX.Element {
56	  const canvasRef = useRef<HTMLCanvasElement>(null);
57	  const rafRef = useRef(0);
58	  const [tool, setTool] = useState<PianoRollTool>("pencil");
59	  const [gridSnap, setGridSnap] = useState<PianoRollGridSnap>("1/8");
60	  const [view, setView] = useState(DEFAULT_VIEW);
61	
62	  const interactions = usePianoRollInteractions(clipId, view, tool, gridSnap);
63	
64	  // Store selectors
65	  const clips = useDawStore((s) => s.clips);
66	  const selectedNoteIds = useDawStore((s) => s.selectedNoteIds);
67	  const cursorSeconds = useDawStore((s) => s.cursorSeconds);
68	  const bpm = useDawStore((s) => s.bpm);
69	  const transportState = useDawStore((s) => s.transportState);
70	
71	  // Derive clip data
72	  const clip = clipId !== null ? clips[clipId] : undefined;
73	  const notes = useMemo(
74	    () => (clip !== undefined && isMidiClip(clip) ? clip.noteEvents : []),
75	    [clip],
76	  );
77	  const clipStartTime = clip !== undefined ? clip.startTime : 0;
78	  const clipDuration = clip !== undefined ? clip.duration : 4;
79	
80	  // Keyboard commands
81	  const { deleteSelectedNotes } = interactions;
82	  const registry = useMemo(() => {
83	    const reg = new CommandRegistry();
84	    reg.register({
85	      id: "piano-roll.tool.pencil",
86	      label: "Pencil Tool",
87	      execute() {
88	        setTool("pencil");
89	      },
90	    });
91	    reg.register({
92	      id: "piano-roll.tool.select",
93	      label: "Select Tool",
94	      execute() {
95	        setTool("select");
96	      },
97	    });
98	    reg.register({
99	      id: "piano-roll.tool.erase",
100	      label: "Erase Tool",
101	      execute() {
102	        setTool("erase");
103	      },
104	    });
105	    reg.register({
106	      id: "piano-roll.delete-selected",
107	      label: "Delete Selected Notes",
108	      execute() {
109	        deleteSelectedNotes();
110	      },
111	    });
112	    return reg;
113	  }, [deleteSelectedNotes]);
114	
115	  const shortcuts = useMemo(() => {
116	    const map = new ShortcutMap();
117	    map.bind({ key: "p", commandId: "piano-roll.tool.pencil" });
118	    map.bind({ key: "s", commandId: "piano-roll.tool.select" });
119	    map.bind({ key: "e", commandId: "piano-roll.tool.erase" });
120	    map.bind({ key: "Delete", commandId: "piano-roll.delete-selected" });
121	    map.bind({ key: "Backspace", commandId: "piano-roll.delete-selected" });
122	    return map;
123	  }, []);
124	
125	  useKeyboardShortcuts(registry, shortcuts);
126	
127	  // Render loop
128	  const render = useCallback((): void => {
129	    const canvas = canvasRef.current;
130	    if (canvas === null) return;
131	    const ctx = canvas.getContext("2d");
132	    if (ctx === null) return;
133	
134	    const rect = canvas.getBoundingClientRect();
135	    renderPianoRoll({
136	      ctx,
137	      width: rect.width,
138	      height: rect.height,
139	      view,
140	      notes,
141	      selectedNoteIds: [...selectedNoteIds],
142	      cursorSeconds,
143	      bpm,
144	      clipStartTime,
145	      clipDuration,
146	      tool,
147	      velocityLaneHeight: PR_VELOCITY_LANE_HEIGHT,
148	    });
149	  }, [
150	    view,
151	    notes,
152	    selectedNoteIds,
153	    cursorSeconds,
154	    bpm,
155	    clipStartTime,
156	    clipDuration,
157	    tool,
158	  ]);
159	
160	  // RAF scheduling
161	  useEffect(() => {
162	    const tick = (): void => {
163	      render();
164	      if (transportState === "playing") {
165	        rafRef.current = requestAnimationFrame(tick);
166	      }
167	    };
168	
169	    rafRef.current = requestAnimationFrame(tick);
170	    return (): void => {
171	      cancelAnimationFrame(rafRef.current);
172	    };
173	  }, [render, transportState]);
174	
175	  // Canvas sizing with ResizeObserver
176	  useEffect(() => {
177	    const canvas = canvasRef.current;
178	    if (canvas === null) return;
179	    const parent = canvas.parentElement;
180	    if (parent === null) return;
181	
182	    const resizeCanvas = (): void => {
183	      const dpr = window.devicePixelRatio;
184	      const rect = parent.getBoundingClientRect();
185	      canvas.width = rect.width * dpr;
186	      canvas.height = rect.height * dpr;
187	      canvas.style.width = `${String(rect.width)}px`;
188	      canvas.style.height = `${String(rect.height)}px`;
189	
190	      const ctx = canvas.getContext("2d");
191	      if (ctx !== null) {
192	        ctx.scale(dpr, dpr);
193	      }
194	      render();
195	    };
196	
197	    if (typeof ResizeObserver === "undefined") return;
198	
199	    const observer = new ResizeObserver(resizeCanvas);
200	    observer.observe(parent);
201	    resizeCanvas();
202	
203	    return (): void => {
204	      observer.disconnect();
205	    };
206	  }, [render]);
207	
208	  // Wheel: ctrl+wheel for zoom, plain wheel for scroll
209	  // Attached via useEffect with { passive: false } so preventDefault() works
210	  useEffect(() => {
211	    const canvas = canvasRef.current;
212	    if (canvas === null) return;
213	
214	    const handleWheel = (e: WheelEvent): void => {
215	      e.preventDefault();
216	
217	      if (e.ctrlKey || e.metaKey) {
218	        const factor = e.deltaY < 0 ? ZOOM_FACTOR : 1 / ZOOM_FACTOR;
219	        setView((prev) => ({
220	          ...prev,
221	          pixelsPerSecond: Math.min(
222	            MAX_PPS,
223	            Math.max(MIN_PPS, prev.pixelsPerSecond * factor),
224	          ),
225	        }));
226	      } else if (e.shiftKey) {
227	        setView((prev) => ({
228	          ...prev,
229	          scrollX: Math.max(0, prev.scrollX + e.deltaY / prev.pixelsPerSecond),
230	        }));
231	      } else {
232	        setView((prev) => ({
233	          ...prev,
234	          scrollX: Math.max(0, prev.scrollX + e.deltaX / prev.pixelsPerSecond),
235	          scrollY: Math.min(
236	            PR_MAX_NOTE,
237	            Math.max(PR_MIN_NOTE, prev.scrollY - e.deltaY / prev.noteHeight),
238	          ),
239	        }));
240	      }
241	    };
242	
243	    canvas.addEventListener("wheel", handleWheel, { passive: false });
244	    return (): void => {
245	      canvas.removeEventListener("wheel", handleWheel);
246	    };
247	  }, []);
248	
249	  return (
250	    <section data-testid="piano-roll-editor" className={styles["container"]}>
251	      <div className={styles["toolbar"]}>
252	        <button
253	          data-testid="tool-pencil"
254	          className={styles["toolButton"]}
255	          data-active={String(tool === "pencil")}
256	          onClick={() => {
257	            setTool("pencil");
258	          }}
259	        >
260	          Pencil
