      view,
      tracks,
      clips,
      selectedClipIds,
      cursorSeconds,
      bpm,
    });
  }, [view, tracks, clips, selectedClipIds, cursorSeconds, bpm]);

  // Schedule re-render when state changes or during playback
  useEffect(() => {
    const tick = (): void => {
      render();
      if (transportState === "playing") {
        rafRef.current = requestAnimationFrame(tick);
      }
    };

    rafRef.current = requestAnimationFrame(tick);
    return (): void => {
      cancelAnimationFrame(rafRef.current);
    };
  }, [render, transportState]);

  // Handle canvas sizing with ResizeObserver
  useEffect(() => {
    const canvas = canvasRef.current;
    if (canvas === null) return;
    const parent = canvas.parentElement;
    if (parent === null) return;

    const resizeCanvas = (): void => {
      const dpr = window.devicePixelRatio;
      const rect = parent.getBoundingClientRect();
      canvas.width = rect.width * dpr;
      canvas.height = rect.height * dpr;
      canvas.style.width = `${String(rect.width)}px`;
      canvas.style.height = `${String(rect.height)}px`;

      const ctx = canvas.getContext("2d");
      if (ctx !== null) {
        ctx.scale(dpr, dpr);
      }
    };

    if (typeof ResizeObserver === "undefined") return;

    const observer = new ResizeObserver(resizeCanvas);
    observer.observe(parent);
    resizeCanvas();

    return (): void => {
      observer.disconnect();
    };
  }, []);

  // Wheel: ctrl+wheel for zoom, plain wheel for scroll
  const handleWheel = useCallback(
    (e: React.WheelEvent<HTMLCanvasElement>): void => {
      e.preventDefault();

      if (e.ctrlKey || e.metaKey) {
        // Zoom
        const factor = e.deltaY < 0 ? ZOOM_FACTOR : 1 / ZOOM_FACTOR;
        setView((prev) => ({
          ...prev,
          pixelsPerSecond: Math.min(
            MAX_PPS,
            Math.max(MIN_PPS, prev.pixelsPerSecond * factor),
          ),
        }));
      } else if (e.shiftKey) {
        // Horizontal scroll
        setView((prev) => ({
          ...prev,
          scrollX: Math.max(0, prev.scrollX + e.deltaY / prev.pixelsPerSecond),
        }));
      } else {
        // Vertical scroll
        setView((prev) => ({
          ...prev,
          scrollX: Math.max(0, prev.scrollX + e.deltaX / prev.pixelsPerSecond),
          scrollY: Math.max(0, prev.scrollY + e.deltaY),
        }));
      }
    },
    [],
  );

  return (
    <section data-testid="arrangement-panel" className={styles["container"]}>
      <canvas
        ref={canvasRef}
        className={styles["canvas"]}
        style={{ cursor: interactions.cursor }}
        onWheel={handleWheel}
        onPointerDown={interactions.onPointerDown}
        onPointerMove={interactions.onPointerMove}
        onPointerUp={interactions.onPointerUp}
        onDoubleClick={interactions.onDoubleClick}
      />
    </section>
  );
}

import { useCallback, useState } from "react";
import { useTransport } from "@audio/use-transport";
import { useDawStore } from "@state/index";
import { BpmInput } from "./BpmInput";
import { CursorDisplay } from "./CursorDisplay";
import styles from "./TransportBar.module.css";

export function TransportBar(): React.JSX.Element {
  const transport = useTransport();
  const transportState = useDawStore((s) => s.transportState);
  const bpm = useDawStore((s) => s.bpm);
  const loopEnabled = useDawStore((s) => s.loopEnabled);
  const setLoop = useDawStore((s) => s.setLoop);
  const [metronomeOn, setMetronomeOn] = useState(false);

  const handleLoopToggle = useCallback((): void => {
    setLoop(!loopEnabled);
  }, [loopEnabled, setLoop]);

  const handleMetronomeToggle = useCallback((): void => {
    const next = !metronomeOn;
    setMetronomeOn(next);
    transport.setMetronomeEnabled(next);
  }, [metronomeOn, transport]);

  const handleBpmChange = useCallback(
    (newBpm: number): void => {
      transport.setBpm(newBpm);
    },
    [transport],
  );

  const isPlaying = transportState === "playing";
  const clock = transport.getClock();
  const tempoMap = clock?.getTempoMap() ?? null;

  return (
    <header data-testid="toolbar" className={styles["transportBar"]}>
      <span className={styles["brand"]}>BRUTALWAV</span>
      <div className={styles["spacer"]} />

      <div className={styles["controls"]}>
        <span className={styles["label"]}>BPM</span>
        <BpmInput value={bpm} onChange={handleBpmChange} />

        <span className={styles["label"]}>4/4</span>

        <button
          type="button"
          className={styles["transportBtn"]}
          data-active={isPlaying}
          aria-label="Play"
          onClick={() => {
            transport.play();
          }}
        >
          {"\u25B6"}
        </button>

        <button
          type="button"
          className={styles["transportBtn"]}
          aria-label="Stop"
          onClick={() => {
            transport.stop();
          }}
        >
          {"\u25A0"}
        </button>

        <CursorDisplay
          transportSAB={transport.getTransportSAB()}
          tempoMap={tempoMap}
        />

        <button
          type="button"
          role="switch"
          aria-checked={loopEnabled}
          aria-label="Loop"
          className={styles["transportBtn"]}
          data-active={loopEnabled}
          onClick={handleLoopToggle}
        >
          LOOP
        </button>

        <div className={styles["metronomeToggle"]}>
          <button
            type="button"
            role="switch"
            aria-checked={metronomeOn}
            aria-label="Metronome"
            className={styles["transportBtn"]}
            data-active={metronomeOn}
            onClick={handleMetronomeToggle}
          >
            MET
          </button>
        </div>
      </div>
    </header>
  );
}

